// DB_Resolve_Service_ID — PRE Validate (SEC02)
const input = $input.first()?.json || {};
const provider_id = Number(input.provider_id || 0);
const service_name = String(input.service_name || '').trim();

if (!provider_id || provider_id <= 0) throw new Error('VALIDATION_ERROR: invalid provider_id');
if (service_name.length < 2) throw new Error('VALIDATION_ERROR: service_name too short');

// Basic safe characters check (no backslashes or strange escapes)
// Allow letters, numbers, spaces, and basic Spanish punctuation
const isSafe = /^[a-zA-Z0-9 áéíóúüñÁÉÍÓÚÜÑ.,?!¿¡\-]{2,200}$/.test(service_name);
if (!isSafe) throw new Error('VALIDATION_ERROR: service_name contains invalid characters');

return [{ json: { provider_id, service_name: service_name.toLowerCase(), original_name: service_name } }];

// Post-Validate + Score Evaluation
const rows = $input.all();
const buildData = $('Build Resolve Query').first()?.json;

if (!rows || rows.length === 0) {
  return [{
    json: {
      resolved: false,
      match_type: 'NOT_FOUND',
      match_score: 0,
      service_id: null,
      service_name: null,
      price: null,
      currency: 'USD',
      candidates: [],
      provider_id: buildData?.provider_id,
      queried_name: buildData?.service_name,
      _meta: {
        source: 'DB_Resolve_Service_ID',
        timestamp: new Date().toISOString(),
        version: '1.0.0'
      }
    }
  }];
}

const best = rows[0]?.json;
const score = Number(best?.match_score ?? 0);

let match_type;
if (score >= 0.8) match_type = 'EXACT';
else if (score >= 0.4) match_type = 'PARTIAL';
else match_type = 'WEAK';

const candidates = rows
  .map(r => ({
    service_id:   r.json?.service_id,
    service_name: r.json?.service_name,
    match_score:  Number(r.json?.match_score ?? 0)
  }))
  .filter(c => c.match_score >= 0.4);

return [{
  json: {
    resolved: score >= 0.4,
    match_type,
    match_score: score,
    service_id:   score >= 0.4 ? best.service_id   : null,
    service_name: score >= 0.4 ? best.service_name : null,
    price:        score >= 0.4 ? best.price        : null,
    currency:     score >= 0.4 ? best.currency     : 'USD',
    candidates,
    provider_id:  buildData?.provider_id,
    queried_name: buildData?.service_name,
    _meta: {
      source: 'DB_Resolve_Service_ID',
      timestamp: new Date().toISOString(),
      version: '1.0.0'
    }
  }
}];

const d = $input.first()?.json;
return [{
  json: {
    success: true,
    error_code: null,
    error_message: null,
    data: {
      resolved:     d.resolved,
      match_type:   d.match_type,
      match_score:  d.match_score,
      service_id:   d.service_id,
      service_name: d.service_name,
      description:  d.description,
      price:        d.price,
      currency:     d.currency,
      candidates:   d.candidates,
      provider_id:  d.provider_id,
      queried_name: d.queried_name
    },
    _meta: {
      source:      'DB_Resolve_Service_ID',
      timestamp:   new Date().toISOString(),
      workflow_id: 'DB_RESOLVE_SVC',
      version:     '1.0.0'
    }
  }
}];

const d = $input.first()?.json;
return [{
  json: {
    success: true,
    error_code: null,
    error_message: null,
    data: {
      resolved: false,
      match_type: d.match_type,
      match_score: d.match_score,
      service_id: null,
      service_name: null,
      candidates: [],
      provider_id: d.provider_id,
      queried_name: d.queried_name
    },
    _meta: {
      source: 'DB_Resolve_Service_ID',
      timestamp: new Date().toISOString(),
      workflow_id: 'DB_RESOLVE_SVC',
      version: '1.0.0'
    }
  }
}];

const input = $input.first()?.json || {};
let errorCode = input.error_code || 'GENERAL_ERROR';
let errorMessage = input.error_message || input.message || 'Unknown error';

return [{
  json: {
    success: false,
    error_code: errorCode,
    error_message: errorMessage,
    data: null,
    _meta: {
      source: 'DB_Resolve_Service_ID',
      timestamp: new Date().toISOString(),
      workflow_id: 'DB_RESOLVE_SVC',
      version: '1.0.0'
    }
  }
}];
